import torch
import spacy

from selfcheckgpt.modeling_selfcheck import SelfCheckNLI

# Load SpaCy model
nlp = spacy.load("en_core_web_sm")

# Main passage generated by an LLM
passage = (
    "Michael Alan Weiner (born March 31, 1942) "
    "is an American radio host. "
    "He is the host of The Savage Nation."
)

# Split passage into sentences
sentences = [sent.text.strip() for sent in nlp(passage).sents]

print("Sentences:")
for i, sent in enumerate(sentences, start=1):
    print(f"{i}. {sent}")

# Sampled passages
sample1 = (
    "Michael Alan Weiner (born March 31, 1942) "
    "is an American radio host. "
    "He is the host of The Savage Country."
)

sample2 = (
    "Michael Alan Weiner (born January 13, 1960) "
    "is a Canadian radio host. "
    "He works at The New York Times."
)

sample3 = (
    "Michael Alan Weiner (born March 31, 1942) "
    "is an American radio host. "
    "He obtained his PhD from MIT."
)

sampled_passages = [sample1, sample2, sample3]

# Device
device = torch.device(
    "cuda" if torch.cuda.is_available() else "cpu"
)

print(f"\nUsing device: {device}")

# Load SelfCheck-NLI
selfcheck_nli = SelfCheckNLI(device=device)

# Predict hallucination scores
sent_scores_nli = selfcheck_nli.predict(
    sentences=sentences,
    sampled_passages=sampled_passages,
)

print("\nSentence-level Hallucination Scores:")
for sentence, score in zip(sentences, sent_scores_nli):
    print(f"\nSentence: {sentence}")
    print(f"Hallucination Score: {score:.6f}")

print("\nRaw Scores:")
print(sent_scores_nli)